import _defineProperty from "@babel/runtime/helpers/esm/defineProperty";
import app from 'flarum/admin/app';
import Component from 'flarum/common/Component';
import Button from 'flarum/common/components/Button';
import LoadingIndicator from 'flarum/common/components/LoadingIndicator';
const t = (k, p) => app.translator.trans('ernestdefoe-calendar.admin.' + k, p);
const api = path => app.forum.attribute('apiUrl') + path;
const PRESETS = ['#3b5bdb', '#e8590c', '#2f9e44', '#9c36b5', '#e03131', '#1098ad', '#f08c00', '#495057'];

// Module-level cache. The admin settings page re-runs customSetting's
// `() => m(CategoryManager)` on every redraw, which remounts this component â€” so
// fetching in oninit + redrawing would loop forever (perpetual spinner + request
// flood). Caching the loaded categories means a remounted instance shows them
// instantly and never re-fetches, breaking the loop.
let CACHE = null;

/**
 * In-place CRUD for event categories, rendered inside the extension's settings
 * page. Talks straight to the JSON API (admin-guarded) so it needs no store
 * models â€” keeping the extension's footprint small.
 */
export default class CategoryManager extends Component {
  constructor() {
    super(...arguments);
    _defineProperty(this, "loading", true);
    _defineProperty(this, "saving", {});
    _defineProperty(this, "cats", []);
    _defineProperty(this, "draft", {
      name: '',
      color: PRESETS[0]
    });
  }
  oninit(vnode) {
    super.oninit(vnode);
    if (CACHE) {
      this.cats = CACHE;
      this.loading = false;
    } else {
      this.load();
    }
  }
  load() {
    this.loading = true;
    app.request({
      method: 'GET',
      url: api('/calendar/categories')
    }).then(res => {
      this.cats = CACHE = res.data || [];
      this.loading = false;
      m.redraw();
    }).catch(() => {
      this.cats = CACHE = [];
      this.loading = false;
      m.redraw();
    });
  }
  view() {
    return m('.CalendarAdmin', [m('label.FormLabel', t('categories')), m('p.helpText', t('categories_help')), this.loading ? m(LoadingIndicator) : m('.CalendarAdmin-categories', [...this.cats.map(c => this.row(c)), this.newRow()])]);
  }
  row(c) {
    return m('.CalendarAdmin-category', {
      key: c.id
    }, [this.swatch(c), m('input.FormControl', {
      value: c.name,
      oninput: e => c.name = e.target.value
    }), Button.component({
      className: 'Button Button--icon',
      icon: 'fas fa-check',
      loading: !!this.saving[c.id],
      disabled: !c.name.trim(),
      onclick: () => this.save(c)
    }), Button.component({
      className: 'Button Button--icon CalendarAdmin-del',
      icon: 'fas fa-trash',
      onclick: () => this.remove(c)
    })]);
  }
  newRow() {
    const d = this.draft;
    // Keyed like the rows above it â€” a fragment can't mix keyed + unkeyed
    // children (Mithril throws "all have keys or none"), which crashed the render.
    return m('.CalendarAdmin-category.CalendarAdmin-new', {
      key: 'new'
    }, [this.swatch(d), m('input.FormControl', {
      value: d.name,
      placeholder: t('category_add'),
      oninput: e => d.name = e.target.value
    }), Button.component({
      className: 'Button Button--primary',
      icon: 'fas fa-plus',
      loading: !!this.saving['new'],
      disabled: !d.name.trim(),
      onclick: () => this.create()
    }, t('category_add'))]);
  }
  swatch(c) {
    return m('.CalendarAdmin-swatchWrap', [m('span.CalendarAdmin-swatch', {
      style: {
        background: c.color
      }
    }), m('input.CalendarAdmin-color', {
      type: 'color',
      value: c.color,
      oninput: e => c.color = e.target.value
    }), m('.CalendarAdmin-presets', PRESETS.map(p => m('button.CalendarAdmin-preset', {
      type: 'button',
      style: {
        background: p
      },
      onclick: () => c.color = p
    })))]);
  }
  save(c) {
    this.saving[c.id] = true;
    app.request({
      method: 'PATCH',
      url: api('/calendar/categories/' + c.id),
      body: {
        data: {
          attributes: {
            name: c.name,
            color: c.color
          }
        }
      }
    }).then(() => {
      this.saving[c.id] = false;
      app.alerts.show({
        type: 'success'
      }, t('category_saved'));
      m.redraw();
    }).catch(() => {
      this.saving[c.id] = false;
      m.redraw();
    });
  }
  create() {
    this.saving['new'] = true;
    app.request({
      method: 'POST',
      url: api('/calendar/categories'),
      body: {
        data: {
          attributes: {
            name: this.draft.name,
            color: this.draft.color
          }
        }
      }
    }).then(res => {
      this.cats.push(res.data);
      CACHE = this.cats;
      this.draft = {
        name: '',
        color: PRESETS[this.cats.length % PRESETS.length]
      };
      this.saving['new'] = false;
      m.redraw();
    }).catch(() => {
      this.saving['new'] = false;
      m.redraw();
    });
  }
  remove(c) {
    if (!confirm(t('category_delete_confirm'))) return;
    app.request({
      method: 'DELETE',
      url: api('/calendar/categories/' + c.id)
    }).then(() => {
      this.cats = CACHE = this.cats.filter(x => x !== c);
      m.redraw();
    }).catch(() => {});
  }
}
flarum.reg.add('ernestdefoe-calendar', 'admin/components/CategoryManager', CategoryManager);